   546→     * @param storeName       the name of the state store
   547→     * @param topologyName    the name of the topology to search for stores within
   548→     * @return topics subscribed from source processors that are connected to these state stores
   549→     */
   550→    public Collection<String> sourceTopicsForStore(final String storeName, final String topologyName) {
   551→        return lookupBuilderForNamedTopology(topologyName).sourceTopicsForStore(storeName);
   552→    }
   553→
   554→    public static String getTopologyNameOrElseUnnamed(final String topologyName) {
   555→        return topologyName == null ? UNNAMED_TOPOLOGY : topologyName;
   556→    }
   557→
   558→    /**
   559→     * @param topologiesToExclude the names of any topologies to exclude from the returned topic groups,
   560→     *                            eg because they have missing source topics and can't be processed yet
   561→     *
   562→     * @return                    flattened map of all subtopologies (from all topologies) to topics info
   563→     */
   564→    public Map<Subtopology, TopicsInfo> subtopologyTopicsInfoMapExcluding(final Set<String> topologiesToExclude) {
   565→        final Map<Subtopology, TopicsInfo> subtopologyTopicsInfo = new HashMap<>();
   566→        applyToEachBuilder(b -> {
   567→            if (!topologiesToExclude.contains(b.topologyName())) {
   568→                subtopologyTopicsInfo.putAll(b.subtopologyToTopicsInfo());
   569→            }
   570→        });
   571→        return subtopologyTopicsInfo;
   572→    }
   573→
   574→    /**
   575→     * @return    map from topology to its subtopologies and their topics info
   576→     */
   577→    public Map<String, Map<Subtopology, TopicsInfo>> topologyToSubtopologyTopicsInfoMap() {
   578→        final Map<String, Map<Subtopology, TopicsInfo>> topologyToSubtopologyTopicsInfoMap = new HashMap<>();
   579→        applyToEachBuilder(b -> topologyToSubtopologyTopicsInfoMap.put(b.topologyName(), b.subtopologyToTopicsInfo()));
   580→        return  topologyToSubtopologyTopicsInfoMap;
   581→    }
   582→
   583→    public Map<String, List<String>> nodeToSourceTopics(final TaskId task) {
   584→        return lookupBuilderForTask(task).nodeToSourceTopics();
   585→    }
   586→
   587→    void addSubscribedTopicsFromMetadata(final Set<String> topics, final String logPrefix) {
   588→        applyToEachBuilder(b -> b.addSubscribedTopicsFromMetadata(topics, logPrefix));
   589→    }
   590→
   591→    void addSubscribedTopicsFromAssignment(final Set<TopicPartition> partitions, final String logPrefix) {
   592→        applyToEachBuilder(b -> b.addSubscribedTopicsFromAssignment(partitions, logPrefix));
   593→    }
   594→
   595→    public Collection<Set<String>> copartitionGroups() {
   596→        final List<Set<String>> copartitionGroups = new ArrayList<>();
   597→        applyToEachBuilder(b -> copartitionGroups.addAll(b.copartitionGroups()));
   598→        return copartitionGroups;
   599→    }
   600→
   601→    /**
   602→     * @return the {@link InternalTopologyBuilder} for this task's topology, guaranteed to be non-null
   603→     *
   604→     * @throws UnknownTopologyException  if the task is from a named topology that this client isn't aware of
   605→     */
   606→    private InternalTopologyBuilder lookupBuilderForTask(final TaskId task) {
   607→        final InternalTopologyBuilder builder = task.topologyName() == null ?
   608→            builders.get(UNNAMED_TOPOLOGY) :
   609→            builders.get(task.topologyName());
   610→        if (builder == null) {
   611→            throw new UnknownTopologyException("Unable to locate topology builder", task.topologyName());
   612→        } else {
   613→            return builder;
   614→        }
   615→    }
   616→
   617→    @SuppressWarnings("deprecation")
   618→    public Collection<NamedTopology> allNamedTopologies() {
   619→        return builders.values()
   620→            .stream()
   621→            .map(InternalTopologyBuilder::namedTopology)
   622→            .collect(Collectors.toSet());
   623→    }
   624→
   625→
   626→    /**
   627→     * @return the InternalTopologyBuilder for the NamedTopology with the given {@code topologyName}
   628→     *         or the builder for a regular Topology if {@code topologyName} is {@code null},
   629→     *         else returns {@code null} if {@code topologyName} is non-null but no such NamedTopology exists
   630→     */
   631→    public InternalTopologyBuilder lookupBuilderForNamedTopology(final String topologyName) {
   632→        return builders.get(getTopologyNameOrElseUnnamed(topologyName));
   633→    }
   634→
   635→    private boolean evaluateConditionIsTrueForAnyBuilders(final Function<InternalTopologyBuilder, Boolean> condition) {
   636→        for (final InternalTopologyBuilder builder : builders.values()) {
   637→            if (condition.apply(builder)) {
   638→                return true;
   639→            }
   640→        }
   641→        return false;
   642→    }
   643→
   644→    private void applyToEachBuilder(final Consumer<InternalTopologyBuilder> function) {
   645→        for (final InternalTopologyBuilder builder : builders.values()) {
   646→            function.accept(builder);
   647→        }
   648→    }
   649→
   650→    public void setMetricsCache(final TopologyMetricsCache cache) {
   651→        this.metricsCache = cache;
   652→    }
   653→
   654→    public TopologyMetricsCache metricsCache() {
   655→        return metricsCache;
   656→    }
   657→
   658→    public static class Subtopology implements Comparable<Subtopology> {
   659→        final int nodeGroupId;
   660→        final String namedTopology;
   661→
   662→        public Subtopology(final int nodeGroupId, final String namedTopology) {
   663→            this.nodeGroupId = nodeGroupId;
   664→            this.namedTopology = namedTopology;
   665→        }
   666→
   667→        @Override
   668→        public boolean equals(final Object o) {
   669→            if (this == o) {
   670→                return true;
   671→            }
   672→            if (o == null || getClass() != o.getClass()) {
   673→                return false;
   674→            }
   675→            final Subtopology that = (Subtopology) o;
   676→            return nodeGroupId == that.nodeGroupId &&
   677→                    Objects.equals(namedTopology, that.namedTopology);
   678→        }
   679→
   680→        @Override
   681→        public int hashCode() {
   682→            return Objects.hash(nodeGroupId, namedTopology);
   683→        }
   684→
   685→        @Override
   686→        public int compareTo(final Subtopology other) {
   687→            if (nodeGroupId != other.nodeGroupId) {
   688→                return Integer.compare(nodeGroupId, other.nodeGroupId);
   689→            }
   690→            if (namedTopology == null) {
   691→                return other.namedTopology == null ? 0 : -1;
   692→            }
   693→            if (other.namedTopology == null) {
   694→                return 1;
   695→            }
   696→
   697→            // Both not null
   698→            return namedTopology.compareTo(other.namedTopology);
   699→        }
   700→    }
   701→}
