366→                log.error("Detected a named topology with no input topics, a named topology may not be empty.");
367→                throw new TopologyException("Topology has no stream threads and no global threads, " +
368→                                                "must subscribe to at least one source topic or pattern.");
369→            }
370→        } else {
371→            // If both the global and non-global topologies are empty, this indicates a bug in user code
372→            if (hasNoLocalTopology() && !hasGlobalTopology()) {
373→                log.error("Topology with no input topics will create no stream threads and no global thread.");
374→                throw new TopologyException("Topology has no stream threads and no global threads, " +
375→                                                "must subscribe to at least one source topic or global table.");
376→            }
377→        }
378→
379→        // Lastly we check for an empty non-global topology and override the threads to zero if set otherwise
380→        if (configuredNumStreamThreads != 0 && hasNoLocalTopology()) {
381→            log.info("Overriding number of StreamThreads to zero for global-only topology");
382→            return 0;
383→        }
384→
385→        return configuredNumStreamThreads;
386→    }
387→
388→    /**
389→     * @return true iff the app is using named topologies, or was started up with no topology at all
390→     */
391→    public boolean hasNamedTopologies() {
392→        return !builders.containsKey(UNNAMED_TOPOLOGY);
393→    }
394→
395→    public Set<String> namedTopologiesView() {
396→        return hasNamedTopologies() ? Collections.unmodifiableSet(builders.keySet()) : emptySet();
397→    }
398→
399→    /**
400→     * @return true iff any of the topologies have a global topology
401→     */
402→    public boolean hasGlobalTopology() {
403→        return evaluateConditionIsTrueForAnyBuilders(InternalTopologyBuilder::hasGlobalStores);
404→    }
405→
406→    /**
407→     * @return true iff any of the topologies have no local (aka non-global) topology
408→     */
409→    public boolean hasNoLocalTopology() {
410→        return evaluateConditionIsTrueForAnyBuilders(InternalTopologyBuilder::hasNoLocalTopology);
411→    }
412→
413→    public boolean hasPersistentStores() {
414→        // If the app is using named topologies, there may not be any persistent state when it first starts up
415→        // but a new NamedTopology may introduce it later, so we must return true
416→        if (hasNamedTopologies()) {
417→            return true;
418→        }
419→        return evaluateConditionIsTrueForAnyBuilders(InternalTopologyBuilder::hasPersistentStores);
420→    }
421→
422→    public boolean hasStore(final String name) {
423→        return evaluateConditionIsTrueForAnyBuilders(b -> b.hasStore(name));
424→    }
425→
426→    public boolean hasOffsetResetOverrides() {
427→        // Return true if using named topologies, as there may be named topologies added later which do have overrides
428→        return hasNamedTopologies() || evaluateConditionIsTrueForAnyBuilders(InternalTopologyBuilder::hasOffsetResetOverrides);
429→    }
430→
431→    public Optional<AutoOffsetResetStrategy> offsetResetStrategy(final String topic) {
432→        for (final InternalTopologyBuilder builder : builders.values()) {
433→            if (builder.containsTopic(topic)) {
434→                return Optional.ofNullable(builder.offsetResetStrategy(topic));
435→            }
436→        }
437→        log.warn("Unable to look up offset reset strategy for topic {} " +
438→            "as this topic does not appear in the sources of any of the current topologies: {}\n " +
439→                "This may be due to natural race condition when removing a topology but it should not " +
440→                "persist or appear frequently.",
441→            topic, namedTopologiesView()
442→        );
443→        // returning `null` for an Optional return type triggers spotbugs
444→        // we added an exception for NP_OPTIONAL_RETURN_NULL for this method
445→        // when we remove NamedTopologies, we can remove this exception
446→        return null;
447→    }
448→
449→
450→    public Collection<String> fullSourceTopicNamesForTopology(final String topologyName) {
451→        Objects.requireNonNull(topologyName, "topology name must not be null");
452→        return lookupBuilderForNamedTopology(topologyName).fullSourceTopicNames();
453→    }
454→
455→    public Collection<String> allFullSourceTopicNames() {
456→        final List<String> sourceTopics = new ArrayList<>();
457→        applyToEachBuilder(b -> sourceTopics.addAll(b.fullSourceTopicNames()));
458→        return sourceTopics;
459→    }
460→
461→    Pattern sourceTopicPattern() {
462→        final StringBuilder patternBuilder = new StringBuilder();
463→
464→        applyToEachBuilder(b -> {
465→            final String patternString = b.sourceTopicPatternString();
466→            if (!patternString.isEmpty()) {
467→                patternBuilder.append(patternString).append("|");
468→            }
469→        });
470→
471→        if (patternBuilder.length() > 0) {
472→            patternBuilder.setLength(patternBuilder.length() - 1);
473→            return Pattern.compile(patternBuilder.toString());
474→        } else {
475→            return EMPTY_ZERO_LENGTH_PATTERN;
476→        }
477→    }
478→
479→    public boolean usesPatternSubscription() {
480→        return evaluateConditionIsTrueForAnyBuilders(InternalTopologyBuilder::usesPatternSubscription);
481→    }
482→
483→    // Can be empty if app is started up with no Named Topologies, in order to add them on later
484→    public boolean isEmpty() {
485→        return builders.isEmpty();
486→    }
487→
488→    public String topologyDescriptionString() {
489→        if (isEmpty()) {
490→            return "";
491→        }
492→        final StringBuilder sb = new StringBuilder();
493→
494→        applyToEachBuilder(b -> sb.append(b.describe().toString()));
495→
496→        return sb.toString();
497→    }
498→
499→    /**
500→     * @return the {@link ProcessorTopology subtopology} built for this task, guaranteed to be non-null
501→     *
502→     * @throws UnknownTopologyException  if the task is from a named topology that this client isn't aware of
503→     */
504→    public ProcessorTopology buildSubtopology(final TaskId task) {
505→        final InternalTopologyBuilder builder = lookupBuilderForTask(task);
506→        return builder.buildSubtopology(task.subtopology());
507→    }
508→
509→    public ProcessorTopology globalTaskTopology() {
510→        if (hasNamedTopologies()) {
511→            throw new IllegalStateException("Global state stores are not supported with Named Topologies");
512→        }
513→        return globalTopology;
514→    }
515→
516→    public Map<String, StateStore> globalStateStores() {
517→        return globalStateStores;
518→    }
519→
520→    public Map<String, List<String>> stateStoreNameToSourceTopicsForTopology(final String topologyName) {
521→        return lookupBuilderForNamedTopology(topologyName).stateStoreNameToFullSourceTopicNames();
522→    }
523→
524→    public Set<String> stateStoreNamesForSubtopology(final String topologyName, final int subtopologyId) {
525→        return lookupBuilderForNamedTopology(topologyName).stateStoreNamesForSubtopology(subtopologyId);
526→    }
527→
528→    public Map<String, List<String>> stateStoreNameToSourceTopics() {
529→        final Map<String, List<String>> stateStoreNameToSourceTopics = new HashMap<>();
530→        applyToEachBuilder(b -> stateStoreNameToSourceTopics.putAll(b.stateStoreNameToFullSourceTopicNames()));
531→        return stateStoreNameToSourceTopics;
532→    }
533→
534→    public String storeForChangelogTopic(final String topicName) {
535→        for (final InternalTopologyBuilder builder : builders.values()) {
536→            final String store = builder.storeForChangelogTopic(topicName);
537→            if (store != null) {
538→                return store;
539→            }
540→        }
541→        log.warn("Unable to locate any store for topic {}", topicName);
542→        return "";
543→    }
544→
545→    /**
546→     * @param storeName       the name of the state store
547→     * @param topologyName    the name of the topology to search for stores within
548→     * @return topics subscribed from source processors that are connected to these state stores
549→     */
550→    public Collection<String> sourceTopicsForStore(final String storeName, final String topologyName) {
551→        return lookupBuilderForNamedTopology(topologyName).sourceTopicsForStore(storeName);
552→    }
553→
554→    public static String getTopologyNameOrElseUnnamed(final String topologyName) {
555→        return topologyName == null ? UNNAMED_TOPOLOGY : topologyName;
556→    }
557→
558→    /**
559→     * @param topologiesToExclude the names of any topologies to exclude from the returned topic groups,
560→     *                            eg because they have missing source topics and can't be processed yet
561→     *
562→     * @return                    flattened map of all subtopologies (from all topologies) to topics info
563→     */
564→    public Map<Subtopology, TopicsInfo> subtopologyTopicsInfoMapExcluding(final Set<String> topologiesToExclude) {
565→        final Map<Subtopology, TopicsInfo> subtopologyTopicsInfo = new HashMap<>();
566→        applyToEachBuilder(b -> {
567→            if (!topologiesToExclude.contains(b.topologyName())) {
568→                subtopologyTopicsInfo.putAll(b.subtopologyToTopicsInfo());
569→            }
570→        });
571→        return subtopologyTopicsInfo;
572→    }
573→
574→    /**
575→     * @return    map from topology to its subtopologies and their topics info
576→     */
577→    public Map<String, Map<Subtopology, TopicsInfo>> topologyToSubtopologyTopicsInfoMap() {
578→        final Map<String, Map<Subtopology, TopicsInfo>> topologyToSubtopologyTopicsInfoMap = new HashMap<>();
579→        applyToEachBuilder(b -> topologyToSubtopologyTopicsInfoMap.put(b.topologyName(), b.subtopologyToTopicsInfo()));
580→        return  topologyToSubtopologyTopicsInfoMap;
581→    }
582→
583→    public Map<String, List<String>> nodeToSourceTopics(final TaskId task) {
584→        return lookupBuilderForTask(task).nodeToSourceTopics();
585→    }
586→
587→    void addSubscribedTopicsFromMetadata(final Set<String> topics, final String logPrefix) {
588→        applyToEachBuilder(b -> b.addSubscribedTopicsFromMetadata(topics, logPrefix));
589→    }
590→
591→    void addSubscribedTopicsFromAssignment(final Set<TopicPartition> partitions, final String logPrefix) {
592→        applyToEachBuilder(b -> b.addSubscribedTopicsFromAssignment(partitions, logPrefix));
593→    }
594→
595→    public Collection<Set<String>> copartitionGroups() {
596→        final List<Set<String>> copartitionGroups = new ArrayList<>();
597→        applyToEachBuilder(b -> copartitionGroups.addAll(b.copartitionGroups()));
598→        return copartitionGroups;
599→    }
600→
601→    /**
602→     * @return the {@link InternalTopologyBuilder} for this task's topology, guaranteed to be non-null
603→     *
604→     * @throws UnknownTopologyException  if the task is from a named topology that this client isn't aware of
605→     */
606→    private InternalTopologyBuilder lookupBuilderForTask(final TaskId task) {
607→        final InternalTopologyBuilder builder = task.topologyName() == null ?
608→            builders.get(UNNAMED_TOPOLOGY) :
609→            builders.get(task.topologyName());
610→        if (builder == null) {
611→            throw new UnknownTopologyException("Unable to locate topology builder", task.topologyName());
612→        } else {
613→            return builder;
614→        }
615→    }
616→
617→    @SuppressWarnings("deprecation")
618→    public Collection<NamedTopology> allNamedTopologies() {
619→        return builders.values()
620→            .stream()
621→            .map(InternalTopologyBuilder::namedTopology)
622→            .collect(Collectors.toSet());
623→    }
624→
625→
626→    /**
627→     * @return the InternalTopologyBuilder for the NamedTopology with the given {@code topologyName}
628→     *         or the builder for a regular Topology if {@code topologyName} is {@code null},
629→     *         else returns {@code null} if {@code topologyName} is non-null but no such NamedTopology exists
630→     */
631→    public InternalTopologyBuilder lookupBuilderForNamedTopology(final String topologyName) {
632→        return builders.get(getTopologyNameOrElseUnnamed(topologyName));
633→    }
634→
635→    private boolean evaluateConditionIsTrueForAnyBuilders(final Function<InternalTopologyBuilder, Boolean> condition) {
636→        for (final InternalTopologyBuilder builder : builders.values()) {
637→            if (condition.apply(builder)) {
638→                return true;
639→            }
640→        }
641→        return false;
642→    }
643→
644→    private void applyToEachBuilder(final Consumer<InternalTopologyBuilder> function) {
645→        for (final InternalTopologyBuilder builder : builders.values()) {
646→            function.accept(builder);
647→        }
648→    }
649→
650→    public void setMetricsCache(final TopologyMetricsCache cache) {
651→        this.metricsCache = cache;
652→    }
653→
654→    public TopologyMetricsCache metricsCache() {
655→        return metricsCache;
656→    }
657→
658→    public static class Subtopology implements Comparable<Subtopology> {
659→        final int nodeGroupId;
660→        final String namedTopology;
661→
662→        public Subtopology(final int nodeGroupId, final String namedTopology) {
663→            this.nodeGroupId = nodeGroupId;
664→            this.namedTopology = namedTopology;
665→        }
666→
667→        @Override
668→        public boolean equals(final Object o) {
669→            if (this == o) {
670→                return true;
671→            }
672→            if (o == null || getClass() != o.getClass()) {
673→                return false;
674→            }
675→            final Subtopology that = (Subtopology) o;
676→            return nodeGroupId == that.nodeGroupId &&
677→                    Objects.equals(namedTopology, that.namedTopology);
678→        }
679→
680→        @Override
681→        public int hashCode() {
682→            return Objects.hash(nodeGroupId, namedTopology);
683→        }
684→
685→        @Override
686→        public int compareTo(final Subtopology other) {
687→            if (nodeGroupId != other.nodeGroupId) {
688→                return Integer.compare(nodeGroupId, other.nodeGroupId);
689→            }
690→            if (namedTopology == null) {
691→                return other.namedTopology == null ? 0 : -1;
692→            }
693→            if (other.namedTopology == null) {
694→                return 1;
695→            }
696→
697→            // Both not null
698→            return namedTopology.compareTo(other.namedTopology);
699→        }
700→    }
701→}
