    36→import java.util.concurrent.atomic.AtomicReference;
    37→
    38→import static org.apache.kafka.streams.internals.StreamsConfigUtils.ProcessingMode.EXACTLY_ONCE_V2;
    39→
    40→public class DefaultTaskExecutor implements TaskExecutor {
    41→
    42→    private class TaskExecutorThread extends Thread implements ProcessingThread {
    43→
    44→        private final AtomicBoolean shutdownRequested = new AtomicBoolean(false);
    45→        private final AtomicReference<KafkaFutureImpl<StreamTask>> taskReleaseRequested = new AtomicReference<>(null);
    46→
    47→        private final Logger log;
    48→
    49→        public TaskExecutorThread(final String name) {
    50→            super(name);
    51→            final String logPrefix = String.format("%s ", name);
    52→            final LogContext logContext = new LogContext(logPrefix);
    53→            log = logContext.logger(DefaultTaskExecutor.class);
    54→        }
    55→
    56→        @Override
    57→        public void run() {
    58→            log.info("Task executor thread started");
    59→            try {
    60→                while (!shutdownRequested.get()) {
    61→                    try {
    62→                        runOnce(time.milliseconds());
    63→                    } catch (final StreamsException e) {
    64→                        handleException(e);
    65→                    } catch (final Exception e) {
    66→                        handleException(new StreamsException(e));
    67→                    }
    68→                }
    69→            } finally {
    70→                if (currentTask != null) {
    71→                    log.debug("Releasing task {} due to shutdown.", currentTask.id());
    72→                    unassignCurrentTask();
    73→                }
    74→
    75→                final KafkaFutureImpl<StreamTask> taskReleaseFuture;
    76→                if ((taskReleaseFuture = taskReleaseRequested.getAndSet(null)) != null) {
    77→                    log.debug("Asked to return current task, but shutting down.");
    78→                    taskReleaseFuture.complete(null);
    79→                }
    80→                log.info("Task executor thread shutdown");
    81→            }
    82→        }
    83→
    84→        private void handleTaskReleaseRequested() {
    85→            final KafkaFutureImpl<StreamTask> taskReleaseFuture;
    86→            if ((taskReleaseFuture = taskReleaseRequested.getAndSet(null)) != null) {
    87→                if (currentTask != null) {
    88→                    log.debug("Releasing task {} upon request.", currentTask.id());
    89→                    final StreamTask unassignedTask = unassignCurrentTask();
    90→                    taskReleaseFuture.complete(unassignedTask);
    91→                } else {
    92→                    log.debug("Asked to return current task, but returned current task already.");
    93→                    taskReleaseFuture.complete(null);
    94→                }
    95→            }
    96→        }
    97→
    98→        private void handleException(final StreamsException e) {
    99→            if (currentTask != null) {
   100→                taskManager.setUncaughtException(e, currentTask.id());
   101→
   102→                log.debug("Releasing task {} due to uncaught exception.", currentTask.id());
   103→                unassignCurrentTask();
   104→            } else {
   105→                // If we do not currently have a task assigned and still get an error, this is fatal for the executor thread
   106→                throw e;
   107→            }
   108→        }
   109→
   110→        private void runOnce(final long nowMs) {
   111→            handleTaskReleaseRequested();
   112→
   113→            if (currentTask == null) {
   114→                currentTask = taskManager.assignNextTask(DefaultTaskExecutor.this);
   115→            }
   116→
   117→            if (currentTask == null) {
   118→                try {
   119→                    taskManager.awaitProcessableTasks(shutdownRequested::get);
   120→                } catch (final InterruptedException ignored) {
   121→                    // Can be ignored, the cause of the interrupted will be handled in the event loop
   122→                }
   123→            } else {
   124→                boolean progressed = false;
   125→
   126→                if (taskExecutionMetadata.canProcessTask(currentTask, nowMs) && currentTask.isProcessable(nowMs)) {
   127→                    if (processTask(currentTask, nowMs, time)) {
   128→                        log.trace("processed a record for {}", currentTask.id());
   129→                        progressed = true;
   130→                    }
   131→                }
   132→
   133→                if (taskExecutionMetadata.canPunctuateTask(currentTask)) {
   134→                    if (currentTask.maybePunctuateStreamTime()) {
   135→                        log.trace("punctuated stream time for task {} ", currentTask.id());
   136→                        progressed = true;
   137→                    }
   138→                    if (currentTask.maybePunctuateSystemTime()) {
   139→                        log.trace("punctuated system time for task {} ", currentTask.id());
   140→                        progressed = true;
   141→                    }
   142→                }
   143→
   144→                if (!progressed) {
   145→                    log.debug("Releasing task {} because we are not making progress.", currentTask.id());
   146→                    unassignCurrentTask();
   147→                }
   148→            }
   149→        }
   150→
   151→        private boolean processTask(final Task task, final long now, final Time time) {
   152→            boolean processed = false;
   153→            try {
   154→                processed = task.process(now);
   155→                if (processed) {
   156→                    log.trace("Successfully processed task {}", task.id());
   157→                    task.clearTaskTimeout();
   158→                    // TODO: enable regardless of whether using named topologies
   159→                    if (taskExecutionMetadata.hasNamedTopologies() && taskExecutionMetadata.processingMode() != EXACTLY_ONCE_V2) {
   160→                        taskExecutionMetadata.addToSuccessfullyProcessed(task);
   161→                    }
   162→                }
   163→            } catch (final TimeoutException timeoutException) {
   164→                // TODO consolidate TimeoutException retries with general error handling
   165→                task.maybeInitTaskTimeoutOrThrow(now, timeoutException);
   166→                log.error(
   167→                    String.format(
   168→                        "Could not complete processing records for %s due to the following exception; will move to next task and retry later",
   169→                        task.id()),
   170→                    timeoutException
   171→                );
   172→            } catch (final TaskMigratedException e) {
   173→                log.info("Failed to process stream task {} since it got migrated to another thread already. " +
   174→                    "Will trigger a new rebalance and close all tasks as zombies together.", task.id());
   175→                throw e;
   176→            } catch (final StreamsException e) {
   177→                log.error(String.format("Failed to process stream task %s due to the following error:", task.id()), e);
   178→                e.setTaskId(task.id());
   179→                throw e;
   180→            } catch (final RuntimeException e) {
