283→        if (taskExecutorThread != null) {
284→            log.debug("Asking {} to hand back task", taskExecutorThread.getName());
285→            if (!taskExecutorThread.taskReleaseRequested.compareAndSet(null, future)) {
286→                throw new IllegalStateException("There was already a task release request registered");
