    34→    private static final Logger log = LoggerFactory.getLogger(StreamsMetricsConnector.class);
    35→
    36→    private final MetricsSessionManager sessionManager;
    37→    private final ConcurrentHashMap<String, Long> topologyFetchTimestamps = new ConcurrentHashMap<>();
    38→
    39→    private volatile boolean transportValid = true;
    40→
    41→    public StreamsMetricsConnector(final MetricsSessionManager sessionManager) {
    42→        this.sessionManager = sessionManager;
    43→    }
    44→
    45→    /**
    46→     * Fetches the latest metrics for the given topology. Under normal
    47→     * conditions this acquires a shared (read) lock, which cannot deadlock.
    48→     * However, when the transport is detected as stale, it falls through to
    49→     * {@link #refreshTransport()}, which acquires the exclusive (write) lock.
    50→     *
    51→     * @param topologyName the name of the topology to fetch metrics for
    52→     * @return a map of metric name to value
    53→     */
    54→    public Map<String, Double> fetchLatestMetrics(final String topologyName) {
    55→        acquireShared();
