package org.apache.kafka.streams.processor.internals;

/**
 * Fray test that reproduces the deadlock between TopologyMetricsCache monitor
 * and the transport write lock in StreamsMetricsConnector.
 *
 * Thread 1: TopologyMetricsCache.getSnapshot() [cache monitor] -> fetchLatestMetrics -> refreshTransport [write lock]
 * Thread 2: performMaintenance [write lock] -> validateSession -> renewSession -> notifyListeners -> invalidateAll [cache monitor]
 */
public class MetricsCacheDeadlockTest {

    public static void main(String[] args) throws Exception {
        // Set up the session manager with a very short TTL so sessions expire quickly
        final MetricsSessionManager sessionManager = new MetricsSessionManager(1L);

        // Create the metrics connector
        final StreamsMetricsConnector connector = new StreamsMetricsConnector(sessionManager);

        // Create the cache backed by this connector
        final TopologyMetricsCache cache = new TopologyMetricsCache(connector, 1L);

        // Register the cache's invalidation listener with the session manager
        // This is the link that creates the cycle:
        // cache -> connector (via fetchLatestMetrics) and
        // sessionManager -> cache (via invalidation listener)
        sessionManager.registerListener(cache.createInvalidationListener());

        // Mark the transport as invalid so Thread 1 will take the slow path
        // (refreshTransport which acquires the write lock)
        connector.markTransportInvalid();

        // Enable rebalancing mode so session renewal changes shards,
        // which triggers the cache invalidation listener
        sessionManager.setRebalancingMode(true);

        // Thread 1: getSnapshot -> acquires cache monitor, then tries write lock
        final Thread thread1 = new Thread(() -> {
            cache.getSnapshot("test-topology");
        }, "thread-cache-fetch");

        // Thread 2: performMaintenance -> acquires write lock, then (via session renewal) tries cache monitor
        final Thread thread2 = new Thread(() -> {
            connector.performMaintenance();
        }, "thread-maintenance");

        thread1.start();
        thread2.start();

        thread1.join(5000);
        thread2.join(5000);

        if (thread1.isAlive() || thread2.isAlive()) {
            System.err.println("DEADLOCK DETECTED: threads did not complete within timeout");
            System.exit(1);
        }
    }
}

